func (m eventDriverStandingMods) WithParentsCascading() EventDriverStandingMod {
	return EventDriverStandingModFunc(func(ctx context.Context, o *EventDriverStandingTemplate) {
		if isDone, _ := eventDriverStandingWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = eventDriverStandingWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewDriverWithContext(ctx, DriverMods.WithParentsCascading())
			m.WithDriver(related).Apply(ctx, o)
		}
		{

			related := o.f.NewEventWithContext(ctx, EventMods.WithParentsCascading())
			m.WithEvent(related).Apply(ctx, o)
		}
		{

			related := o.f.NewSeasonWithContext(ctx, SeasonMods.WithParentsCascading())
			m.WithSeason(related).Apply(ctx, o)
		}
	})
}

